### 4. **PCI Probe Flow**

When a device with ID 0x2526 is detected, the driver follows this flow:

#### **Step 1: Initial Probe** ([`drv.c:1142-1182`](https://sourcegraph.sourcegraph.com/r/github.com/torvalds/linux/-/blob/drivers/net/wireless/intel/iwlwifi/pcie/drv.c?L1142-L1182))

```c
static int iwl_pci_probe(struct pci_dev *pdev, const struct pci_device_id *ent)
{
    // Get the basic mac_cfg from PCI ID table
    const struct iwl_mac_cfg *mac_cfg = (void *)ent->driver_data;

    // Read hardware revision from BAR0
    hw_rev = readl(hw_base + CSR_HW_REV);

    // Call the probe handler with basic config
    return iwl_pci_gen1_2_probe(pdev, ent, mac_cfg, hw_base, hw_rev);
}
```

#### **Step 2: Detailed Probe** ([`trans.c:4156-4292`](https://sourcegraph.sourcegraph.com/r/github.com/torvalds/linux/-/blob/drivers/net/wireless/intel/iwlwifi/pcie/gen1_2/trans.c?L4156-L4292))

```c
int iwl_pci_gen1_2_probe(struct pci_dev *pdev,
                         const struct pci_device_id *ent,
                         const struct iwl_mac_cfg *mac_cfg, ...)
{
    // Read RF ID from hardware
    info.hw_rf_id = iwl_read32(iwl_trans, CSR_HW_RF_ID);

    // For 9000+ series, may need to map RF ID from version register
    if (iwl_trans->mac_cfg->device_family >= IWL_DEVICE_FAMILY_9000 &&
        !CSR_HW_RFID_TYPE(info.hw_rf_id))
        map_crf_id(iwl_trans, &info);

    // Find specific device info based on hardware characteristics
    dev_info = iwl_pci_find_dev_info(
        pdev->device,                           // 0x2526
        pdev->subsystem_device,                 // OEM-specific subdevice ID
        CSR_HW_RFID_TYPE(info.hw_rf_id),       // RF type (JF1/JF2/...)
        CSR_HW_RFID_IS_CDB(info.hw_rf_id),     // CDB support
        IWL_SUBDEVICE_RF_ID(pdev->subsystem_device),
        IWL_SUBDEVICE_BW_LIM(pdev->subsystem_device),
        !iwl_trans->mac_cfg->integrated         // Discrete vs integrated
    );

    if (dev_info) {
        iwl_trans->cfg = dev_info->cfg;  // Set RF config
        info.name = dev_info->name;       // Set device name
    }

    // Start firmware loading
    iwl_trans->drv = iwl_drv_start(iwl_trans);
}
```

#### **Step 3: Device Info Lookup** ([`drv.c:1095-1140`](https://sourcegraph.sourcegraph.com/r/github.com/torvalds/linux/-/blob/drivers/net/wireless/intel/iwlwifi/pcie/drv.c?L1095-L1140))

```c
const struct iwl_dev_info *
iwl_pci_find_dev_info(u16 device, u16 subsystem_device, u16 rf_type, ...)
{
    // Iterate through iwl_dev_info_table[] in REVERSE order
    for (i = num_devices - 1; i >= 0; i--) {
        const struct iwl_dev_info *dev_info = &iwl_dev_info_table[i];

        // Match device ID (or IWL_CFG_ANY)
        if (dev_info->device != IWL_CFG_ANY && 
            dev_info->device != device)
            continue;

        // Match subdevice with masking
        subdevice_mask = GENMASK(dev_info->subdevice_m_h,
                                 dev_info->subdevice_m_l);
        if (dev_info->subdevice != IWL_CFG_ANY &&
            dev_info->subdevice != (subsystem_device & subdevice_mask))
            continue;

        // Match RF type if specified
        if (dev_info->match_rf_type && dev_info->rf_type != rf_type)
            continue;

        // Match other characteristics (CDB, RF_ID, bandwidth, discrete)
        // ... additional checks ...

        return dev_info;  // Found matching entry
    }
    return NULL;
}
```

### 5. **Firmware Loading**

#### **Step 1: Start Firmware Request** ([`iwl-drv.c:1913-1957`](https://sourcegraph.sourcegraph.com/r/github.com/torvalds/linux/-/blob/drivers/net/wireless/intel/iwlwifi/iwl-drv.c?L1913-L1957))

```c
struct iwl_drv *iwl_drv_start(struct iwl_trans *trans)
{
    struct iwl_drv *drv = kzalloc(sizeof(*drv), GFP_KERNEL);
    drv->trans = trans;

    // Request firmware asynchronously
    ret = iwl_request_firmware(drv, true);
    return drv;
}
```

#### **Step 2: Firmware Name Generation** ([`iwl-drv.c:186-291`](https://sourcegraph.sourcegraph.com/r/github.com/torvalds/linux/-/blob/drivers/net/wireless/intel/iwlwifi/iwl-drv.c?L186-L291))

```c
const char *iwl_drv_get_fwname_pre(struct iwl_trans *trans, char *buf)
{
    // If fw_name_pre is set in config, use it
    if (trans->cfg->fw_name_pre)
        return trans->cfg->fw_name_pre;

    // Otherwise, generate from hardware IDs
    switch (CSR_HW_REV_TYPE(trans->info.hw_rev)) {
    case IWL_CFG_MAC_TYPE_PU:
        mac = "9000-pu";
        mac_step = 'b';
        break;
    case IWL_CFG_MAC_TYPE_TH:
        mac = "9260-th";   // For 9260
        mac_step = 'b';
        break;
    // ...
    }

    switch (CSR_HW_RFID_TYPE(trans->info.hw_rf_id)) {
    case IWL_CFG_RF_TYPE_JF1:
    case IWL_CFG_RF_TYPE_JF2:
        rf = "jf";
        rf_step = 'b';
        break;
    // ...
    }

    // Generate: "iwlwifi-<mac>-<mac_step>0-<rf>-<rf_step>0"
    // Example: "iwlwifi-9260-th-b0-jf-b0"
    scnprintf(buf, FW_NAME_PRE_BUFSIZE,
              "iwlwifi-%s-%c0-%s%s-%c0",
              mac, mac_step, rf, cdb, rf_step);

    return buf;
}
```

